        GREETINGS_I_AM_CAMPAIGN_ARBITER_FOR_THE_ALLIED                        = 7203,  -- Greetings. I am , Campaign Arbiter for the Allied Forces.
        TO_ENSURE_PROMPT_TRANSPORTATION_TO_THE_FRONTLINES_I                   = 7204,  -- To ensure prompt transportation to the frontlines, I have been given clearance to teleport troops to locations on the Quon and Mindartia theaters.
        PLEASE_SELECT_A_DESTINATION_I_DO_NOT_REQUIRE                          = 7205,  -- Please select a destination: I do not require your services. Xarcabard [y|z/ySanz/yBasz/yWinz/yBstz] Beaucedine Glacier[y|z/ySanz/yBasz/yWinz/yBstz] Batallia Downs [y|z/ySanz/yBasz/yWinz/yBstz] Rolanberry Fields [y|z/ySanz/yBasz/yWinz/yBstz] Sauromugue Champaign [y|z/ySanz/yBasz/yWinz/yBstz] Jugner Forest [y|z/ySanz/yBasz/yWinz/yBstz] Pashhow Marshlands [y|z/ySanz/yBasz/yWinz/yBstz] Meriphataud Mountains [y|z/ySanz/yBasz/yWinz/yBstz] Vunkerl Inlet [y|z/ySanz/yBasz/yWinz/yBstz] Grauberg [y|z/ySanz/yBasz/yWinz/yBstz] Fort Karugo-Narugo [y|z/ySanz/yBasz/yWinz/yBstz] East Ronfaure [y|z/ySanz/yBasz/yWinz/yBstz] North Gustaberg [y|z/ySanz/yBasz/yWinz/yBstz] West Sarutabaruta [y|z/ySanz/yBasz/yWinz/yBstz] Southern San d'Oria [y|z/ySanz/yBasz/yWinz/yBstz] Bastok Markets [y|z/ySanz/yBasz/yWinz/yBstz] Windurst Waters [y|z/ySanz/yBasz/yWinz/yBstz] Garlaige Citadel [y|z/ySanz/yBasz/yWinz/yBstz] Crawlers' Nest [y|z/ySanz/yBasz/yWinz/yBstz] Eldieme Necropolis [y|z/ySanz/yBasz/yWinz/yBstz]
        THAT_AREA_IS_CURRENTLY_UNDER_CONTROL                                  = 7206,  -- That area is currently under [San d'Orian/Bastokan/Windurstian/beastman] control.
        I_WILL_REQUIRE_A_TELEPORTATION_FEE_OF_ALLIED                          = 7207,  -- I will require a teleportation fee of # Allied Note[/s]. I see you currently possess #.
