        CARRY_THE_MARK_OF_THE_CRIMSON_LION_WITH                               = 7211,  -- Carry the mark of the crimson lion with pride!
        MAY_THE_FLAMES_OF_FREEDOM_BURN_FOR_ETERNITY                           = 7212,  -- May the flames of freedom burn for eternity!
        LET_THE_KNOWLEDGE_OF_THE_STAR_SIBYL_GUIDE                             = 7213,  -- Let the knowledge of the Star Sibyl guide you to victory!
        YOU_ARE_NOW_PARTICIPATING_IN_THE_ALLIED_CAMPAIGN                      = 7214,  -- You are now participating in the Allied Campaign.
        GREETINGS_I_AM_OF_THE_SAN_D_ORIAN                                     = 7215,  -- Greetings. I am of the San d'Orian Provincial Knights.
        GREETINGS_I_AM_OF_THE_BASTOKAN_LEGION                                 = 7216,  -- Greetings. I am of the Bastokan Legion.
        GREETINGS_I_AM_OF_THE_FEDERATION_OF_WINDURST                          = 7217,  -- Greetings. I am of the Federation of Windurst.
        GREETINGS_I_AM_CAMPAIGN_ARBITER_FOR_THE_ALLIED_2                      = 7218,  -- Greetings. I am , Campaign Arbiter for the Allied Forces.
        WHAT_CAN_I_HELP_YOU_WITH_NOTHING_PERFORMANCE                          = 7219,  -- What can I help you with? Nothing. Performance assessment. New Allied Tags. Temporary items. Union registration. Teleportation. Information on the Allied Campaign.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_NOTHING_I                                 = 7220,  -- What would you like to know? Nothing. I'm sorry. About performance assessment. About Allied Tags. About temporary items. About Unions.
        I_AM_SORRY_BUT_AT_THIS_TIME_I                                         = 7221,  -- I am sorry, but at this time, I cannot be of any assistance in that area.
        UNDERSTOOD_I_SHALL_NOW_JUDGE_YOUR_PERFORMANCE_AND                     = 7222,  -- Understood. I shall now judge your performance and award the proper remuneration.
        AH_I_M_SORRY_TO_INFORM_YOU_THAT                                       = 7223,  -- Ah, I'm sorry to inform you that your performance has not earned you any compensation.
        UNDERSTOOD_I_SHALL_PREPARE_A_NEW_SET_OF                               = 7224,  -- Understood. I shall prepare a new set of tags for you now.
        YOU_VE_ALREADY_UNDERGONE_AN_EVALUATION_FOR_THIS                       = 7225,  -- You've already undergone an evaluation for this battle, or had you forgotten? As much as I'd like to, I'm forbidden from providing you with a new set of Allied Taegs until the next battle begins.
        ANYONE_WEARING_ALLIED_TAGS_WHILE_PARTICIPATING_IN_A                   = 7226,  -- Anyone wearing Allied Tags while participating in a campaign battle will be judged on their overall performance.
        SOLDIERS_WILL_BE_EVALUATED_NOT_ONLY_ON_THEIR                          = 7227,  -- Soldiers will be evaluated not only on their fighting skills, but also on how much they contribute to the efforts of their allies through means such as healing and enhancing.
        HOWEVER_BEWARE_THAT_IF_YOU_LEAVE_THE_AREA                             = 7228,  -- However, beware that if you leave the area before being assessed, you will be deemed a deserter and will forfeit all rewards earned that day.
        ALSO_WHILE_THERE_ARE_NO_IMMEDIATE_PENALTIES_FOR                       = 7229,  -- Also, while there are no immediate penalties for being knocked out, falling in battle will significantly lower the score given to you.
        WHEN_YOU_ARE_READY_TO_RECEIVE_COMPENSATION_FOR                        = 7230,  -- When you are ready to receive compensation for your work on the field, return to me and I shall assess your performance and provide you with your payment.
        ALLIED_TAGS_ARE_A_SPECIAL_TYPE_OF_IDENTIFICATION                      = 7231,  -- Allied Tags are a special type of identification given to all participants of Allied Campaign battles.
        THERE_ARE_BENEFITS_AS_WELL_AS_DRAWBACKS_TO                            = 7232,  -- There are benefits, as well as drawbacks, to wearing the tags. One of the benefits is that in the case you are knocked out on the battlefield, you will not lose any experience points.
        HOWEVER_SOME_OF_THE_DRAWBACKS_INCLUDE_THE_INABILITY                   = 7233,  -- However, some of the drawbacks include the inability to improve skills and earn experience points for individual kills, as well as the right to loot fallen enemies.
        TEMPORARY_ITEMS_CAN_BE_PURCHASED_IN_EXCHANGE_FOR                      = 7234,  -- Temporary items can be purchased in exchange for Allied Notes.
        THERE_ARE_SEVERAL_DIFFERENT_VARIETIES_OF_ITEMS_BUT                    = 7235,  -- There are several different varieties of items, but they all have one thing in common--they can only be used on the battlefield they were issued.
        IT_IS_HIGHLY_RECOMMENDED_THAT_YOU_FIRST_SURVEY                        = 7236,  -- It is highly recommended that you first survey a battle's conditions and then select the supplies that you believe will benefit you most.
        PLEASE_REMEMBER_THAT_ALL_TEMPORARY_ITEMS_YOU_CARRY                    = 7237,  -- Please remember that all temporary items you carry on your person will be confiscated in the event that you leave the area.
        YOU_CAN_ONLY_PURCHASE_TEMPORARY_ITEMS_IF_YOUR                         = 7238,  -- You can only purchase temporary items if your nation of allegiance is commanding the campaign.
        THAT_IS_ALL                                                           = 7239,  -- That is all.
        I_WILL_REQUIRE_A_TELEPORTATION_FEE_OF_ALLIED_2                        = 7240,  -- I will require a teleportation fee of # Allied Note[/s]. I see you currently possess #.
        COMPLETE_TRANSACTION_AND_RETURN_TO_CAPITAL_YES_NO                     = 7241,  -- Complete transaction and return to capital? Yes. No.
        UNDERSTOOD_GOOD_WORK_TODAY                                            = 7242,  -- Understood. Good work today, %.
        THE_GATE_IS_LOCKED                                                    = 7243,  -- The gate is locked.
        YOU_CANNOT_PERFORM_THAT_ACTION_NOW                                    = 7244,  -- You cannot perform that action now.
        I_CANNOT_HELP_YOU_NOW_I_HAVE_OTHER                                    = 7245,  -- I cannot help you now. I have other orders to carry out.
        DON_T_HURT_POOR_GELTPIX_GELTPIX_S_JUST                                = 7246,  -- Don't hurt poor Geltpix! Geltpix's just a merchant from Boodlix's Emporium in Jeuno. Kingdom vendors don't like gil, but Boodlix knows true value of new money.
        BLINGBRIX_GOOD_GOBBIE_FROM_BOODLIX_S_BOODLIX_S                        = 7247,  -- Blingbrix good Gobbie from Boodlix's! Boodlix's Emporium help fighting fighters and maging mages. Gil okay, okay?
        BOODLIX_S_EMPORIUM_OPEN_FOR_BUSINESS_BOODLIX_S                        = 7248,  -- Boodlix's Emporium open for business! Boodlix's gots whats you wants, at the price yous likes! It's okay, we takes yours gils, too!
        HEH_HEH_HEH_NO_SHOOT_NO_SLICE_DIBSTIX                                 = 7249,  -- Heh heh heh! No shoot! No slice! Dibstix good Gobbie. Good Gobbie from Boodlix's Emporium sell you goodies, yeah? Gil okay. Gil okay!
        LOLLYSPOX_BE_BEASTMAN_BUT_LOLLYSPOX_LOVE_ALTANA_ALTANA                = 7250,  -- Lollyspox be beastman, but Lollyspox love Altana. Altana make Lollyspox rich with sparklies from heavens. You make me rich, too?
        MIGHT_YOU_BE_A_STUDENT_OF_THE_SAME                                    = 7251,  -- Might you be a student of the same field as I? If that is the case, I might be able to provide you with the proper grimoires...at a price, of course.
        SPONDULIX_COMES_ALL_THE_WAY_FROM_BOODLIX_S                            = 7252,  -- Spondulix comes all the way from Boodlix's Emporium to help Tarutaru and Mithra. I can help you, too! You have gil, no?
        THE_CAMPAIGN_BATTLE_IN_THIS_AREA_HAS_ALREADY                          = 7253,  -- The campaign battle in this area has already come to a close. I suggest you return to the barracks and rest up for the next operation.
        LET_ME_SHOW_YOU_THE_LIST_OF_ITEMS                                     = 7254,  -- Let me show you the list of items currently available to you.
        SELECT_A_CATEGORY_QUIT_NOTE_ITEMS_NOTE_ITEMS                          = 7255,  -- Select a category: Quit. #-Note Items. #-Note Items. #-Note Items.
