        YOU_CURRENTLY_POSSESS_ALLIED_NOTE                                     = 7257,  -- You currently possess # Allied Note[/s].
        PROCEED_WITH_THE_TRANSACTION_YES_NO                                   = 7258,  -- Proceed with the transaction? Yes. No.
