        I_AM_SORRY_BUT_OUR_STOREROOMS_ARE_EMPTY                               = 7260,  -- I am sorry, but our storerooms are empty. You will have to wait until the next supply unit has arrived.
        THE_CAMPAIGN_BATTLE_HAS_ENDED_THE_TEMPORARY_ITEM                      = 7261,  -- The campaign battle has ended. The temporary item had no effect.
        OBTAINED_TEMPORARY_ITEM_2                                             = 7262,  -- Obtained temporary item: %!
        YOU_HAVE_EARNED_ALLIED_NOTE                                           = 7263,  -- You have earned # Allied Note[/s]!
        YOUR_REPUTATION_WITHIN_THE_ALLIED_CAMPAIGN_HAS_RISEN                  = 7264,  -- Your reputation within the Allied Campaign has risen by #!
        I_AM_SORRY_BUT_YOUR_CAMPAIGN_MEDAL_HAS                                = 7265,  -- I am sorry, %, but your campaign medal has expired. I cannot issue tags to anyone not authorized by the Allied Forces. Return to your nation's capital and speak with a Campaign Evaluation Official.
        OH_HO_KEEN_TO_JOIN_A_UNION_ARE                                        = 7266,  -- Oh ho! Keen to join a Union, are we? Very well. Listen up and I shall tell you all you need to know.
        IN_ORDER_TO_BETTER_COORDINATE_ALLIED_EFFORTS_AGAINST                  = 7267,  -- In order to better coordinate Allied efforts against the beastman menace, we have instituted a system of ad hoc tactical regiments called Unions. With five units to a battlefield, union registration is open to any proven soldier in possession of Allied Tags.
