        THERE_IS_NO_ESCAPE_SAVE_DEATH                                         = 7660,  -- There is no escape...save death!
        ALTANA_LET_YOUR_DIVINE_LIGHT_GUIDE_US_TO                              = 7661,  -- Altana! Let your divine light guide us to victory!
        YOU_BARBARIANS_WILL_REGRET_THE_DAY_YOU_SET                            = 7662,  -- You barbarians will regret the day you set foot on Bastokan soil!
        RYAAAAAAAAAH                                                          = 7663,  -- Ryaaaaaaaaah!
        MEN_DO_NOT_FEAR_THE_ENEMY_IT_IS                                       = 7664,  -- Men! Do not fear the enemy! It is our blades they shall fear!
        A_SWIFT_END_IS_THE_ONLY_MERCY_YOU                                     = 7665,  -- A swift end is the only mercy you will receive from me, fiends!
        WATCH_CAREFULLY_BECAUSE_THIS_IS_THE_LAST_THING                        = 7666,  -- Watch carefully, because this is the last thing you'll ever see in this life!
        I_NEVER_LIKED_FIGHTING_ON_LAND_NOW_GIVE                               = 7667,  -- I never liked fighting on land... Now, give me a well armed battleship on the open sea, and I'll have those turtlebacks running for their lives!
        A_SOLDIER_ALWAYS_COMES_PREPARED_HEHEHEHE                              = 7668,  -- A soldier always comes prepared! Hehehehe!
        TO_YOUR_SEATS_BOYS_THE_SHOW_IS_ABOUT                                  = 7669,  -- To your seats, boys! The show is about to begin!
        AHAHAHAHA_MY_HAND_SLIPPED                                             = 7670,  -- Ahahahaha! My hand slipped!
        THIS_IS_YOUR_LAST_CHANCE_THROW_DOWN_YOUR                              = 7671,  -- This is your last chance. Throw down your weapons and your life will be spared. If you refuse...
        THE_GATES_TO_THE_UNDERWORLD_HAVE_OPENED_I                             = 7672,  -- The gates to the underworld have opened! I'll see you on the other side...or not! Wahahahahah!
        THERE_IS_NOTHING_MORE_MAGNIFICENT_THAN_THE_DANCE                      = 7673,  -- There is nothing more magnificent than the dance of flames on the battlefield!
        PHEW_I_THINK_I_VE_HAD_ENOUGH_OF                                       = 7674,  -- <Phew!> I think I've had enough of this volume!
        GUTTLER_GUTTLER_THIRSTY_GUTTLER_WANT_BLOOD_MORE_BLOOD                 = 7675,  -- Guttler: Guttler thirsty! Guttler want blood! More blood!
        TIME_TO_GO_TO_WORK                                                    = 7676,  -- Time to go to work!
        INVINCIBLE_INDESTRUCTIBLE_INDUBITABLE_THE_AGE_OF_THE_CARDIANS         = 7677,  -- Invincible! Indestructible! Indubitable! The age of the Cardians is upon us!
        YOU_OVER_THERE_NO_WAIT_YOU_RE_SUPPOSED                                = 7678,  -- You, over there. No, wait! You're supposed to be on that side! Hold on, which one were you again? Arrrghhh!
        SNORRRE_IS_THAT_THE_BEST_YOU_CAN_DO                                   = 7679,  -- <Snorrre>... Is that the best you can do?
        PETTY_BEASTMAN_HORDES_ARE_NOTHING_COMPARED_TO_GIANT                   = 7680,  -- Petty beastman hordes are nothing compared to giant wildebeests of homeland! I swat you all down like fruit flies!
        YAWN_UM_HOLY_LIGHT_SHOW_THE_WAY                                       = 7681,  -- <Yawn>... Um... Holy light...show the way...?
        THE_PROTECTION_OF_THE_THRONE_COMES_BEFORE_ALL                         = 7682,  -- The protection of the throne comes before all else. Only by direct order of the royaulais will I wield my blade on the battlefield. Such is the duty of the Royal Guards.
        HAH_HAH_HAH_THE_RINGING_OF_STEEL_UPON                                 = 7683,  -- Hah hah hah! The ringing of steel upon steel! The dripping stench of the battlefield! What could be better than war? The nobles can have their balls, I'll do my dance on the front lines!
        HOW_DARE_A_BASEBORN_PEASANT_RAISE_HIS_HER                             = 7684,  -- How dare a baseborn peasant raise his/her] voice to a noble knight!? Begone, before I strike you down myself!
        THE_KINGDOM_S_DEFEAT_AT_JUGNER_STILL_STINGS                           = 7685,  -- The Kingdom's defeat at Jugner still stings. To avenge the souls of those lost on that fateful day, we must join hands and take up arms as one.
        NOT_ONCE_IN_THE_FOUR_HUNDRED_YEARS_SINCE                              = 7686,  -- Not once in the four hundred years since the dawn of the Royal Knights has the Kingdom found itself in such peril. Let us take up our pikes and stand our ground to ensure another four centuries of prosperity!
        IT_IS_OFTEN_IN_TIMES_OF_STRIFE_THAT                                   = 7687,  -- It is often in times of strife that a man's true nature is revealed. Will you stand tall in the face of fear, or run and cower in the wake of your mother's dress?
        WHILE_OUR_HOLY_DOCTRINES_SPECIFICALLY_PROHIBIT_THE_TAKING             = 7688,  -- While our holy doctrines specifically prohibit the taking of another life, you need not hesitate on the battlefield. The Church has branded the beastmen enemies of Altana. The purification must begin! It is the will of the Goddess!!!
        AFTER_YEARS_OF_TRAINING_IN_THE_FAR_EAST                               = 7689,  -- After years of training in the Far East, I return only to find my nation burning at the hands of the infernal beastman hordes. The heathens shall pay dearly... My work has only just begun.
        YOU_HAVE_THE_LOOK_OF_A_FINE_WARRIOR                                   = 7690,  -- You have the look of a fine warrior. It is a pity you are not one of my Crimson Wolves.
        THE_EYES_OF_THE_GODDESS_ARE_EVER_UPON                                 = 7691,  -- The eyes of the Goddess are ever upon us. We must remain steadfast against the evils from without, as well as those from within.
        THE_REPUBLIC_WAS_FORMED_WITH_THE_BLOOD_AND                            = 7692,  -- The Republic was formed with the blood and sweat of the people. The flames of freedom must continue to light our furnaces of strength. The waters of civilization must continue to turn our wheels of ingenuity!
        TURTLE_SLEEPS_IN_A_ROCKY_DENT_CAUSE_HE                                = 7693,  -- Turtle sleeps in a rocky dent 'Cause he's not a citizent Strike him down with sword and stavet Stick a blue flag in his gravet
        WE_MAY_HAVE_THE_UPPER_HAND_IN_TECHNOLOGY                              = 7694,  -- We may have the upper hand in technology and munitions, but the enemy's advantage lies in their sheer numbers. The Allied Campaign will not win in a day, soldier. Make every bullet count.
        THE_METALWORKS_STRATEGIES_ARE_TOO_TIMID_FOR_MY                        = 7695,  -- The Metalworks' strategies are too timid for my taste. The beastmen are nothing but dominoes, waiting to be toppled. A swift, aggressive assault is the only way to victory.
        MOVE_ALONG_SOLDIER_I_HAVE_NOTHING_TO_SAY                              = 7696,  -- Move along, soldier. I have nothing to say to you.
        HALT_IF_YOU_RE_NOT_ONE_OF_THE                                         = 7697,  -- Halt! If you're not one of the Fourth, then get your sorry tail over to the recruitment office on the double! And if you are one of us, then what the hell are you doing here talking to me!? Get back on the battlefield! About...FACE!
        HEAVY_INFANTRY_FIVE_COLUMNS_OF_200_TWO_100                            = 7698,  -- ...Heavy infantry, five columns of 200... Two 100-knight regiments... Enemy force casualties estimated at 5,000... Oh, I apologize, soldier. I've spent the past few nights preparing for a joint operation with San d'Oria's Royal Knights.
        YOU_LOOK_LIKE_YOU_VE_SEEN_BETTER_DAYS                                 = 7699,  -- You look like you've seen better days, soldier. Let me guess, it's the war that's bringing you down. What you need is a little music in your life!
        IF_IT_WEREN_T_FOR_THE_GALKAN_HEAVY                                    = 7700,  -- If it weren't for the Galkan heavy infantry, this nation wouldn't last a month against the turtlebacks. And what thanks do we get? A handful of stale army biscuits!
        HAVE_YOU_EVER_STOPPED_TO_PONDER_WHAT_THAT                             = 7701,  -- Have you ever stopped to ponder what that comet might truly portend? I'd like to believe it is a message of hope--that soon this age of darkness will come to a close...
        OH_WHATEVER_HAS_BECOME_OF_MY_SWEET_WINDURST                           = 7702,  -- Oh, whatever has become of my sweet Windurst? Rabble running through the streets, streets overrun with rabble! Why are you even speaking to me!? Does the title Master Caster no longer garner even an onz of respect!?
        AH_THE_FATES_HAVE_BROUGHT_YOU_TO_GARIRI                               = 7703,  -- Ah, the Fates have brought you to Gariri the Magnificent! Why am I thus called, you ask? Why, because only I was magnificent enough to decryptify those mysteriously marvelous Near Eastern tomes and open a window to...the Other Side!
        WE_ALL_WEAR_MASKS_BECAUSE_DEEP_DOWN_INSIDE                            = 7704,  -- We all wear masks because deep down inside we are nothing but beasts. The question I ask you is, to which do you submit--the mask, or the beast?
        GUTTLER_I_TOLD_YOU_TO_KEEP_QUI_AHAHAHAH                               = 7705,  -- (Guttler! I told you to keep qui--) Ahahahah... Don't mind me, I was just...uh...keeping myself company! (Shhh! If you open your mouth one more ti--) Ahahaha... Uh, were you still there?
        IF_ONLY_THE_PARLIAMENT_OF_PATRIARCHS_WOULD_LOOSEN                     = 7706,  -- If only the Parliament of Patriarchs would loosen the strings on their purses a little more, I would be outside right now roasting up a couple birdmen to snack on!
        HAVE_FUN_WHILE_YOU_CAN_FILTHY_MERCENARY_BECAUSE                       = 7707,  -- Have fun while you can, filthy mercenary, because before long you'll be back on the streets where you belong--replaced by a quiet, obedient army of Cardians!
        NORMALLY_IT_IS_MY_DUTY_TO_PROTECT_THE                                 = 7708,  -- Normally, it is my duty to protect the patriarchs of parliament, but with the fate of Windurst in doubt, I'm forced to lead my loyal pets to the front lines.
        DO_YOU_LIKE_THE_HEADPIECE_I_MADE_IT                                   = 7709,  -- Do you like the headpiece? I made it from my firrrst victim. I wear it to let everrryone know what happens when they cross Mikhe Aryohcha!
        BACK_IN_MY_HOME_ULBUKA_I_HEAR_RUMORS                                  = 7710,  -- Back in my home, Ulbuka, I hear rumors of great riches in eastern lands. But now I am here, and where are riches? I see nothing but Tarus! Ahahahaha!
        YAAAWN_MASTERING_THESE_NEAR_EASTERN_MAGICS_CAN_BE                     = 7711,  -- <Yaaawn>... Mastering these Near Eastern magics can be quite taxing. If I had a choice, I'd rather be back in bed, relaxing...
        I_SAVED_THIS_ONE_ESPECIALLY_FOR_YOU                                   = 7712,  -- I saved this one especially for you!
        HIIIIII_YAH                                                           = 7713,  -- Hiiiiii-yah!
        MY_DEAR_PUPIL_DALZAKK_YOU_STILL_HAVE_MUCH                             = 7714,  -- My dear pupil, Dalzakk. You still have much to learn...
        WITNESS_THE_TRUE_EMBODIMENT_OF_MY_SORROW                              = 7715,  -- Witness the true embodiment of my sorrow.
        HEH_HEH_HEH                                                           = 7716,  -- Heh heh heh!
        GIGGLE                                                                = 7717,  -- <Giggle>...
        WHEHEHEHEH_YOU_THIRSTY_KOPEH                                          = 7718,  -- Wheheheheh! You thirsty, Kopeh?
        COME_KILHWCH_WE_MUST_STRIKE_DOWN_THE_EVIL                             = 7719,  -- Come, Kilhwch! We must strike down the evil which stands before us!
        MY_BROTHERS_AND_SISTERS_RAISE_YOUR_BLADES_FOR                         = 7720,  -- My brothers and sisters! Raise your blades for justice!
        KILHWCH_SILENCE_THOSE_FIENDS                                          = 7721,  -- Kilhwch! Silence those fiends!
        TO_YOUR_FEET_KILHWCH                                                  = 7722,  -- To your feet, Kilhwch!
        LADY_ULLA_WE_MUST_RETREAT                                             = 7723,  -- Lady Ulla. We must retreat.
        HOW_DARE_YOU                                                          = 7724,  -- How dare you!
        THE_RAVEN_SHALT_SPARE_NARY_A_TEAR_FOR                                 = 7725,  -- The raven shalt spare nary a tear for thy demise.
        WATCH_AND_SEE_HOW_A_REAL_MERCENARY_EARRRNS                            = 7726,  -- Watch! And see how a real mercenary earrrns her wage!
        LEAVE_ME_BE_THE_VERGE_OF_BATTLE_IS                                    = 7727,  -- Leave me be. The verge of battle is no time for words.
        FEAR_NOT_MY_FISTS_WILL_GUIDE_US_TO                                    = 7728,  -- Fear not. My fists will guide us to victory.
        MY_DAUGHTER_AWAITS_HER_FATHER_AT_HOME_I                               = 7729,  -- My daughter awaits her father at home. I will permit no Beastman to delay my return.
        BEYOND_THIS_POINT_LIES_THE_SEALED_ROYAL_TOMB                          = 7730,  -- Beyond this point lies the sealed royal tomb of King Ranperre. Tell me, %, do you believe the legends?
        THE_ORC_WAR_MACHINE_DRAWS_NEAR_WE_MUST                                = 7731,  -- The Orc war machine draws near. We must brace ourselves for battle.
        IN_FORMER_TIMES_THIS_ISLAND_WAS_INHABITED_BY                          = 7732,  -- In former times, this island was inhabited by a ferocious tribe of vikings. It is said they braved vast expanses of open sea to arrive here. Romantic, don't you think?
        SURELY_YOU_HAVE_SEEN_THE_TIGERS_THAT_ROAM                             = 7733,  -- Surely you have seen the tigers that roam these downs. They were brought from the northern continent by the Orcs themselves. They are highly prized for their luxurious pelts, though their bloodlust makes them formidable game.
        THE_BROTHERHOOD_OF_THIS_PLACE_ONCE_WELCOMED_ME                        = 7734,  -- The brotherhood of this place once welcomed me long ago. I pray that the years have been kind to them.
        THE_GOLD_MUSKETEERS_OF_THE_REPUBLICAN_ARMY_ARE                        = 7735,  -- The Gold Musketeers of the Republican Army are marshalled by young woman. Such talk is sure to inspire my daughter.
        BASTOK_WAS_FORCED_TO_ABANDON_THE_PALBOROUGH_MINES                     = 7736,  -- Bastok was forced to abandon the Palborough Mines following a Beastman invasion. How an army such as the Republic's could permit such an affront baffles me to no end.
        THE_VILLAGE_ELDER_IN_LA_VAULE_TOLD_ME                                 = 7737,  -- The village elder in La Vaule told me of the so-called wyrm deity of Grauberg. Of course, I am sure it is nothing more than folktales. Still, my curiosity is piqued...
        STRANGE_I_AM_CERTAIN_THE_VEGETATION_OF_THIS                           = 7738,  -- Strange... I am certain the vegetation of this area is different from when I last visited. Surely I would not have allowed myself to forget such beautiful flowers.
        SUCH_DEVASATION_EVEN_THE_RESILIENT_GOOBBUE_WERE_NOT                   = 7739,  -- Such devasation... Even the resilient Goobbue were not able to survive. I wonder if this place shall ever be restored to its former glory...
        HISTORY_TELLS_US_THAT_IT_WAS_IN_THE                                   = 7740,  -- History tells us that it was in the year 381 that San d'Oria's iron-tempered King Lanfeaur R d'Oraguille came these lands to strike a peace with the Quadav. Whatever happened to the bond that was formed...?
        I_HAVE_SEEN_HERE_TWO_TWINS_WHO_BETWEEN                                = 7741,  -- I have seen here two twins who between them share a power for magic the likes of which I have never seen. This is indeed a strange nation.
        UNFORTUNATE_I_HAD_ALWAYS_WISHED_TO_GAZE_UPON                          = 7742,  -- Unfortunate... I had always wished to gaze upon the fabled magic towers of West Sarutabaruta with my own eyes. Yet I fear I may be too late...
        THIS_FORTRESS_IS_LAUDED_AS_THE_IMPREGNABLE_POINT                      = 7743,  -- This fortress is lauded as the impregnable point of Windurst's defenses. Goddess forbid, should it happen to be taken, Windurst is unlikely to last more than a month's time.
        THESE_WINDBLOWN_SANDS_REAK_HAVOC_ON_MY_THROAT                         = 7744,  -- These windblown sands reak havoc on my throat. I look forward to a cup of my daughter's fine Batallia tea.
        TAKE_HEED_I_HAVE_SEEN_BEASTMAN_DUG_BATTLE                             = 7745,  -- Take heed, %. I have seen Beastman-dug battle trenches throughout these plains. Should you be found, your life is forfeit.
        THERE_IS_AN_OMINOUS_FEELING_IN_THE_AIR                                = 7746,  -- There is an ominous feeling in the air... This is no place to linger.
        NEVER_HAVE_I_FELT_A_COLD_AS_PIERCING                                  = 7747,  -- Never have I felt a cold as piercing as this. My teeth chatter and my toes grow numb. We would do well to find a place to warm ourselves.
        I_WONDER_IF_IT_WAS_NOT_SOMEWHERE_NEAR                                 = 7748,  -- I wonder if it was not somewhere near here where minister Francmage was dispatched on the Multinational Expedition some 10 years ago.
        NEVER_DID_I_IMAGINE_THE_DAY_WOULD_COME                                = 7749,  -- Never did I imagine the day would come that I would set foot in this accursed place. Has great is our foe's desperation? Do not lower your guard, %.
        AND_SO_WE_BREACH_THE_ENEMY_S_INNER                                    = 7750,  -- And so we breach the enemy's inner sanctum. Expect anything, %! And don't die on me!
        AS_THE_ALLIED_FORCES_HAVE_LONG_MAINTAINED_THIS                        = 7751,  -- As the Allied Forces have long maintained, this citadel would be ideally suited to the defense of Jeuno.
        A_WELL_CONCEIVED_STRATEGY_A_STRONGHOLD_ESTABLISHED_UNDER              = 7752,  -- A well conceived strategy... A stronghold established under the cover of the nest of these vile crawlers. It is almost surely to be overlooked by the enemy.
        OH_MIGHTY_ALTANA_BE_THE_SWORD_IN_MY                                   = 7753,  -- Oh, mighty Altana, be the sword in my hand. With you, the swift cannot flee, nor the strong escape. Receive mine enemies, for the mercy of the Goddess embraces even the wicked.
        HEH_HEH_HEH_WONDER_WHAT_TECHNIQUE_I_SHOULD                            = 7754,  -- Heh heh heh! Wonder what technique I should try out on these ol' beastmen chumps.
        HAHA_WHO_WILL_BE_THE_NEXT_DARLING_RECIPIENT                           = 7755,  -- Haha... Who will be the next darling recipient of my spells?
        RED_BLOOD_BLUE_BLOOD_ANY_COLORRR_BLOOD_IF                             = 7756,  -- Red blood, blue blood, any colorrr blood. If it bleeds, we can kill it!
        WHAT_S_TAKING_SO_LONG_I_M_GETTING                                     = 7757,  -- What's taking so long? I'm getting all antsy-wantsy! My pets are I are all bad at staying still...
        DO_NOT_FEAR_RIGHTEOUSNESS_WILL_PREVAIL_I_SHALL                        = 7758,  -- Do not fear. Righteousness will prevail. I shall show you victory!
        PROMISE_ME_ONE_THING_SHOULD_ANYTHING_HAPPEN_TO                        = 7759,  -- Promise me one thing. Should anything happen to me... Look after my daughter.
        I_RECKON_I_LL_BE_EARNIN_MY_KEEP                                       = 7760,  -- I reckon I'll be earnin' my keep. Won't be doin' nothin' extra, though. Don't be expectin' me to risk my hide without my due an' proper, mm-hmmm.
        BRAVO_REALLY_IS_A_DEAR_ONCE_YOU_GET                                   = 7761,  -- Bravo really is a dear once you get to know him. It's just that in the heat of battle he... Well, you'll see.
        MY_BLADE_KYOMON_ANTICIPATES_MUCH_BEASTMAN_BLOOD_THIS                  = 7762,  -- My blade, Kyomon, anticipates much beastman blood. This battle may prove interesting, yet.
        LOOK_TO_ME_MORTALS_AND_BE_HAUNTED_FOR                                 = 7763,  -- Look to me, mortals! And be haunted for the rest of your brief time in this world!
        FOR_A_SPLIT_SECOND_YOU_THOUGHT_YOU_SAW                                = 7764,  -- For a split second, you thought you saw Titania turn and shoot you a tiny smile.
        THE_FLOWER_ATOP_BABBAN_NY_MHEILLEA_S_HEAD                             = 7765,  -- The flower atop Babban Ny Mheillea's head appears to be in full bloom!
        RIBBIT_RIBBIT_2                                                       = 7766,  -- Ribbit! Ribbit!
        YOU_D_BETTER_WATCH_YOUR_BACK                                          = 7767,  -- You'd better watch your back!
        DON_T_TAKE_THIS_PERSONALLY_BUT_I_VE                                   = 7768,  -- Don't take this personally, but I've got children to feed.
        TIME_TO_HAVE_SOME_FUN                                                 = 7769,  -- Time to have some fun!
        RECKON_IT_S_TIME_TUH_EARN_MY_KEEP                                     = 7770,  -- Reckon it's time tuh earn my keep, mm-hmm.
        COME_NOW_BRAVO_IT_S_HIGH_TIME_WE                                      = 7771,  -- Come now, Bravo! It's high time we taught these beasts what a wyvern is truly capable of!
        HEHE_SO_MANY_WILLING_TO_BE_SACRIFICED                                 = 7772,  -- Hehe, so many willing to be sacrificed!
        HMPH_PERHAPS_I_SHOULD_JUST_BURN_THE_EYES                              = 7773,  -- Hmph. Perhaps I should just burn the eyes of these infidels with my true form.
        I_FEAR_NOT_DEATH_FOR_THE_GODDESS_AWAITS                               = 7774,  -- I fear not death, for the Goddess awaits us with open arms.
        IT_IS_NOT_YET_YOUR_TIME                                               = 7775,  -- It is not yet your time.
        BE_STRONG_FOR_THE_GODDESS_IS_WITH_YOU                                 = 7776,  -- Be strong, for the Goddess is with you, always.
        RETURN_TO_THE_DUST_WHENCE_YOU_CAME_RANDGRITH                          = 7777,  -- Return to the dust whence you came! Randgrith!!!
        SAINTS_AND_HEROES_GLORY_AND_DESPAIR_OF_THESE                          = 7778,  -- Saints and heroes...glory and despair... Of these I shall sing unto my dying breath.
        TWHEN_WORK_HAS_ENDED_STAY_NOT_LATE_RETURN                             = 7779,  -- tWhen work has ended stay not late. @Return to where thy dearest awaits.
        TO_GENTLE_GODDESS_OF_THE_DAWN_THOU_BRIGHTEN                           = 7780,  -- tO gentle Goddess of the Dawn, thou brighten the black of night. @Hear our song and heed our call, and bathe us in your delight.
        TPRESS_FORWARD_VALIANT_SOLDIERS_GLORY_DRAWS_NEARER_STILL              = 7781,  -- tPress forward valiant soldiers, glory draws nearer still. @Thy deeds shall resound forever, by my stirring song fulfilled.
        TLOYAL_CHILDREN_OF_ALTANA_ARISE_AND_BE_SUSTAINED                      = 7782,  -- tLoyal children of Altana, arise and be sustained. @Be nourished in thine undying faith, and bask in victory's refrain.
        TSING_DANCE_LAUGH_AND_CRY_LET_SWEAT_RAIN                              = 7783,  -- tSing! Dance! Laugh, and cry! Let sweat rain down in floods! @Ride upon this rhythmic beat, make seethe thy red life blood!
        TDANCE_THINE_ELEGANT_AIRY_STEPS_THAT_HAS_WON                          = 7784,  -- tDance thine elegant, airy steps that has won a thousand hearts. @Enchant, enthrall, and captivate, treat none with disregard.
        HONORED_AM_I_TO_HAVE_THIS_CHANCE_TO                                   = 7785,  -- Honored am I to have this chance to share the same stage with you.
        ARMY_UNIT_DEPLOYED_TO                                                 = 7786,  -- [Sand/Bas/Win/Orc/Quad/Yag/Kindred]Army Unit # deployed to [Sand/Ronfa/ugner/Vunkerl/Batallia/La Vaule/Necro/Bastok/Gusta/Grauberg/Passhow/Rolanberry/Beadeaux/Crawler/Win/Saruta/Fort K/Meriphataud/Sauromugue/Oztroja/G Citadel/Glacier/Xarca/Zvahl Out/Zvahl In/Throne Room]...
        ARMY_UNIT_IS_RESTING_FOR_MINUTE_S                                     = 7787,  -- [San d'Orian/Bastokan/Windurstian/Orcish/Quadav/Yagudo/Kindred]Army Unit # is resting for # minute(s)...
        TALLYING_CAMPAIGN_RESULTS                                             = 7788,  -- Tallying Campaign Results...
        ARMY_UNIT_LEAVES_RESULT                                               = 7789,  -- [San d'Orian/Bastokan/Windurstian/Orcish/Quadav/Yagudo/Kindred]Army Unit # leaves. Result: [Victory/Defeat...]
        ARMY_FREELANCE_LEAVES_RESULT                                          = 7790,  -- [San d'Orian/Bastokan/Windurstian/Orcish/Quadav/Yagudo/Kindred]Army freelance # leaves. Result: [Victory/Defeat...]
        UNIT_NO_DEPLOYING_IN_MINUTE_S                                         = 7791,  -- Unit No.#: Deploying in # minute(s)
        UNIT_NO_READYING_POP                                                  = 7792,  -- Unit No.#: Readying pop.
        UNIT_NO_PERSON_POP                                                    = 7793,  -- Unit No.#: #-person pop.
        UNIT_NO_LOSES                                                         = 7794,  -- Unit No.# loses!
        UNIT_NO_WINS                                                          = 7795,  -- Unit No.# wins!
        TALLYING_CAMPAIGN_RESULTS_2                                           = 7796,  -- Tallying Campaign results...
        CAMPAIGN_RESULTS_TALLIED                                              = 7797,  -- Campaign results tallied.
