        THE_CAMPAIGN_BATTLE_HAS_ENDED                                         = 7799,  -- The Campaign battle has ended.
        THE_BEASTMAN_CONFEDERATE_FORCES_HAVE_RETREATED                        = 7800,  -- The Beastman Confederate forces have retreated!
        THE_ALLIED_FORCES_OF_ALTANA_HAVE_RETREATED                            = 7801,  -- The Allied Forces of Altana have retreated...
        OBJECTIVE_COMPLETED_REPORT_TO_SIR_RASDINICE_IN_SOUTHERN               = 7802,  -- Objective completed. Report to Sir Rasdinice in Southern San d'Oria.
        OBJECTIVE_COMPLETED_REPORT_TO_FIRST_CENTURION_HIERONYMUS_IN           = 7803,  -- Objective completed. Report to First Centurion Hieronymus in the Bastok Markets.
        OBJECTIVE_COMPLETED_REPORT_TO_EMHI_TCHAORYO_IN_WINDURST               = 7804,  -- Objective completed. Report to Emhi Tchaoryo in Windurst Waters.
        OBJECTIVE_FAILED_REPORT_TO_SIR_RASDINICE_IN_SOUTHERN                  = 7805,  -- Objective failed. Report to Sir Rasdinice in Southern San d'Oria.
